static enum MHD_Result send_json_with_headers(struct MHD_Connection *connection,
                                             const char *body,
                                             unsigned int status_code,
                                             const char *extra_header_name,
                                             const char *extra_header_value) {
    struct MHD_Response *response = MHD_create_response_from_buffer(
        strlen(body), (void *)body, MHD_RESPMEM_MUST_COPY);
    if (!response) return MHD_NO;

    MHD_add_response_header(response, "Content-Type", "application/json");
    MHD_add_response_header(response, "Access-Control-Allow-Origin", "*");
    MHD_add_response_header(response, "Access-Control-Allow-Methods",
                            "GET, POST, PUT, DELETE, OPTIONS");
    MHD_add_response_header(response, "Access-Control-Allow-Headers",
                            "Content-Type, X-API-Key");

    if (extra_header_name && extra_header_value)
        MHD_add_response_header(response, extra_header_name, extra_header_value);

    enum MHD_Result ret = MHD_queue_response(connection, status_code, response);
    MHD_destroy_response(response);
    return ret;
}

static enum MHD_Result send_json(struct MHD_Connection *connection,
                                const char *body,
                                unsigned int status_code) {
    return send_json_with_headers(connection, body, status_code, NULL, NULL);
}

static enum MHD_Result send_json_total(struct MHD_Connection *connection,
                                      const char *body,
                                      unsigned int status_code,
                                      int total) {
    char total_str[64];
    snprintf(total_str, sizeof(total_str), "%d", total);
    return send_json_with_headers(connection, body, status_code, "X-Total-Count", total_str);
}

static enum MHD_Result send_text(struct MHD_Connection *connection,
                                const char *text,
                                unsigned int status_code) {
    struct MHD_Response *response = MHD_create_response_from_buffer(
        strlen(text), (void *)text, MHD_RESPMEM_MUST_COPY);
    if (!response) return MHD_NO;
    MHD_add_response_header(response, "Content-Type", "text/plain; charset=utf-8");
    enum MHD_Result ret = MHD_queue_response(connection, status_code, response);
    MHD_destroy_response(response);
    return ret;
}

static enum MHD_Result send_file_text(struct MHD_Connection *connection, const char *path) {
    FILE *f = fopen(path, "rb");
    if (!f) return send_text(connection, "Not Found", MHD_HTTP_NOT_FOUND);

    fseek(f, 0, SEEK_END);
    long n = ftell(f);
    fseek(f, 0, SEEK_SET);
    if (n < 0 || n > 1024 * 1024) {
        fclose(f);
        return send_text(connection, "Server Error", MHD_HTTP_INTERNAL_SERVER_ERROR);
    }

    char *buf = (char *)calloc((size_t)n + 1, 1);
    if (!buf) {
        fclose(f);
        return send_text(connection, "Server Error", MHD_HTTP_INTERNAL_SERVER_ERROR);
    }

    size_t r = fread(buf, 1, (size_t)n, f);
    fclose(f);
    buf[r] = '\0';

    enum MHD_Result ret = send_text(connection, buf, MHD_HTTP_OK);
    free(buf);
    return ret;
}

static int parse_int(const char *s, int *out) {
    if (!s || !*s) return 0;
    char *end = NULL;
    long v = strtol(s, &end, 10);
    if (end == s) return 0;
    if (v < -2147483648L || v > 2147483647L) return 0;
    *out = (int)v;
    return 1;
}

static int parse_id_from_url(const char *url, int *out_id) {
    const char *pfx = "/api/notes/";
    size_t n = strlen(pfx);
    if (strncmp(url, pfx, n) != 0) return 0;
    const char *idstr = url + n;
    if (!*idstr) return 0;
    int id = 0;
    if (!parse_int(idstr, &id)) return 0;
    if (id <= 0) return 0;
    *out_id = id;
    return 1;
}

static void coninfo_free(struct ConInfo *ci) {
    if (!ci) return;
    free(ci->buf);
    free(ci);
}

static enum MHD_Result init_con_info(void **con_cls) {
    struct ConInfo *ci = (struct ConInfo *)calloc(1, sizeof(struct ConInfo));
    if (!ci) return MHD_NO;
    ci->cap = 4096;
    ci->buf = (char *)calloc(ci->cap, 1);
    if (!ci->buf) {
        free(ci);
        return MHD_NO;
    }
    *con_cls = ci;
    return MHD_YES;
}

static int json_extract_string(const char *json, const char *key, char **out) {
    *out = NULL;
    if (!json || !key) return 0;

    // Very small, naive JSON string extractor for {"key":"value"}
    // Handles escaped quotes (\") and backslashes.
    char pat[128];
    snprintf(pat, sizeof(pat), "\"%s\"", key);
    const char *p = strstr(json, pat);
    if (!p) return 0;
    p += strlen(pat);
    while (*p && isspace((unsigned char)*p)) p++;
    if (*p != ':') return 0;
    p++;
    while (*p && isspace((unsigned char)*p)) p++;
    if (*p != '"') return 0;
    p++;

    size_t cap = 256;
    size_t len = 0;
    char *buf = (char *)malloc(cap);
    if (!buf) return 0;

    while (*p) {
        if (*p == '"') {
            p++;
            break;
        }
        char c = *p;
        if (c == '\\') {
            p++;
            if (!*p) break;
            char e = *p;
            if (e == '"' || e == '\\' || e == '/') c = e;
            else if (e == 'n') c = '\n';
            else if (e == 'r') c = '\r';
            else if (e == 't') c = '\t';
            else c = e;
        }
        if (len + 2 > cap) {
            cap *= 2;
            char *nb = (char *)realloc(buf, cap);
            if (!nb) { free(buf); return 0; }
            buf = nb;
        }
        buf[len++] = c;
        p++;
    }
    buf[len] = '\0';
    *out = buf;
    return 1;
}

static enum MHD_Result handle_post_put_body(struct MHD_Connection *connection,
                                           const char *method,
                                           const char *url,
                                           const char *upload_data,
                                           size_t *upload_data_size,
                                           void **con_cls) {
    struct ConInfo *ci = (struct ConInfo *)(*con_cls);
    if (!ci) return MHD_NO;

    if (*upload_data_size != 0) {
        if (ci->len + *upload_data_size + 1 > ci->cap) {
            size_t ncap = ci->cap;
            while (ncap < ci->len + *upload_data_size + 1) ncap *= 2;
            char *nbuf = (char *)realloc(ci->buf, ncap);
            if (!nbuf) return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
            ci->buf = nbuf;
            ci->cap = ncap;
        }
        memcpy(ci->buf + ci->len, upload_data, *upload_data_size);
        ci->len += *upload_data_size;
        ci->buf[ci->len] = '\0';
        *upload_data_size = 0;
        return MHD_YES;
    }

    char *title = NULL;
    char *content = NULL;
    (void)json_extract_string(ci->buf, "title", &title);
    (void)json_extract_string(ci->buf, "content", &content);

    if (!title) {
        free(content);
        return send_json(connection, "{\"error\":\"bad request\"}", MHD_HTTP_BAD_REQUEST);
    }

    if (strcmp(method, "POST") == 0) {
        int id = create_note(title, content ? content : "");
        free(title);
        free(content);
        if (id <= 0) return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        char *saved = get_note_json(id);
        if (!saved) return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        enum MHD_Result r = send_json(connection, saved, MHD_HTTP_CREATED);
        free(saved);
        return r;
    }

    if (strcmp(method, "PUT") == 0) {
        int id = 0;
        if (!parse_id_from_url(url, &id)) {
            free(title);
            free(content);
            return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        }
        if (!note_exists(id)) {
            free(title);
            free(content);
            return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        }
        if (!update_note(id, title, content ? content : "")) {
            free(title);
            free(content);
            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        }
        free(title);
        free(content);
        char *saved = get_note_json(id);
        if (!saved) return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        enum MHD_Result r = send_json(connection, saved, MHD_HTTP_OK);
        free(saved);
        return r;
    }

    free(title);
    free(content);
    return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
}

enum MHD_Result route_request(struct MHD_Connection *connection, const char *url,
                              const char *method, const char *upload_data,
                              size_t *upload_data_size, void **con_cls) {
    if (strcmp(method, "OPTIONS") == 0)
        return send_json(connection, "", MHD_HTTP_OK);

    if (strcmp(method, "GET") == 0 && strcmp(url, "/config/api.key") == 0)
        return send_file_text(connection, API_KEY_PATH);

    // Serve static assets from /app/www
    if (strcmp(method, "GET") == 0) {
        enum MHD_Result r = serve_static(connection, url);
        if (r != MHD_NO) return r;
    }

    // API
    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "GET") == 0) {
        int limit = NOTES_DEFAULT_PAGE_SIZE;
        int offset = 0;
        const char *q_limit = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "limit");
        const char *q_offset = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "offset");
        if (q_limit) parse_int(q_limit, &limit);
        if (q_offset) parse_int(q_offset, &offset);
        if (limit <= 0) limit = NOTES_DEFAULT_PAGE_SIZE;
        if (limit > NOTES_MAX_PAGE_SIZE) limit = NOTES_MAX_PAGE_SIZE;
        if (offset < 0) offset = 0;

        int total = get_total_notes_count();
        char *json = get_notes_paginated_json(limit, offset);
        if (!json) return send_json_total(connection, "[]", MHD_HTTP_OK, total);
        enum MHD_Result rr = send_json_total(connection, json, MHD_HTTP_OK, total);
        free(json);
        return rr;
    }

    int id = 0;
    if (strcmp(method, "GET") == 0 && parse_id_from_url(url, &id)) {
        char *json = get_note_json(id);
        if (!json) return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        enum MHD_Result rr = send_json(connection, json, MHD_HTTP_OK);
        free(json);
        return rr;
    }

    if (strcmp(method, "POST") == 0 && strcmp(url, "/api/notes") == 0) {
        if (!api_key_valid(connection))
            return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);

        const char *cl = MHD_lookup_connection_value(connection, MHD_HEADER_KIND, "Content-Length");
        if (cl) {
            int v = 0;
            if (parse_int(cl, &v) && v > NOTES_MAX_BODY_BYTES)
                return send_json(connection, "{\"error\":\"payload too large\"}", MHD_HTTP_CONTENT_TOO_LARGE);
        }

        if (*con_cls == NULL) return init_con_info(con_cls);
        enum MHD_Result rr = handle_post_put_body(connection, method, url, upload_data, upload_data_size, con_cls);
        if (*upload_data_size == 0) {
            coninfo_free((struct ConInfo *)*con_cls);
            *con_cls = NULL;
        }
        return rr;
    }

    if (strcmp(method, "PUT") == 0 && strncmp(url, "/api/notes/", 11) == 0) {
        if (!api_key_valid(connection))
            return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);

        const char *cl = MHD_lookup_connection_value(connection, MHD_HEADER_KIND, "Content-Length");
        if (cl) {
            int v = 0;
            if (parse_int(cl, &v) && v > NOTES_MAX_BODY_BYTES)
                return send_json(connection, "{\"error\":\"payload too large\"}", MHD_HTTP_CONTENT_TOO_LARGE);
        }

        if (*con_cls == NULL) return init_con_info(con_cls);
        enum MHD_Result rr = handle_post_put_body(connection, method, url, upload_data, upload_data_size, con_cls);
        if (*upload_data_size == 0) {
            coninfo_free((struct ConInfo *)*con_cls);
            *con_cls = NULL;
        }
        return rr;
    }

    if (strcmp(method, "DELETE") == 0 && parse_id_from_url(url, &id)) {
        if (!api_key_valid(connection))
            return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
        if (!note_exists(id))
            return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        if (!delete_note(id))
            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        return send_json(connection, "{\"status\":\"deleted\"}", MHD_HTTP_OK);
    }

    return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
}
